const item = $input.item.json;

// 1. Lógica de Captura Robusta
// Buscamos o valor onde a API realmente o coloca
const valor = item.licitacao?.valor || item.valor || 0;

// Buscamos o processo onde a API realmente o coloca
const processo = item.licitacao?.numeroProcesso || item.numeroProcesso || "Não informado";

// 2. Lógica de Auditoria (Mantida, agora com o valor correto)
let alerta = "Normal";
const modalidade = item.modalidadeLicitacao || "Não informada";

if (modalidade.includes("Dispensa") && valor > 50000) {
    alerta = "⚠️ Valor alto para Dispensa de Licitação";
} else if (valor > 1000000) {
    alerta = "💰 Contrato Milionário: Requer Atenção";
} else if (valor > 500000) {
    alerta = "👀 Valor Expressivo: Verificar Detalhes";
}

// 3. Retorno para o Postgres
return {
    json: {
        id: item.id,
        data_auditoria: new Date().toISOString(),
        orgao_nome: item.unidadeGestora?.orgaoMaximo?.nome || "Órgão não identificado",
        unidade_gestora: item.unidadeGestora?.nome || "Unidade não identificada",

        // Agora pegando da variável 'processo' que extraímos acima
        numero_processo: processo,

        objeto_original: item.licitacao?.objeto || "Sem descrição",
        modalidade: modalidade,

        // Agora pegando da variável 'valor' que extraímos acima
        valor_estimado: valor, 

        resumo_cidadao: "Resumo disponível sob demanda no painel.",
        fidelidade_nota: 10,
        alerta_auditoria: alerta,
        link_fonte: `https://portaldatransparencia.gov.br/licitacoes/${item.id}`,
        agente_responsavel_id: null,
        categoria_gasto: null,
        agente_autorizador_id: null
    }
};

// 1. Configurações Iniciais
const apiKey = 'a872c438262a647dfe89cd3c531c2cb0'.trim();

// 2. Período de Teste (Janeiro de 2024 - Validado)
const dataInicio = "01/01/2024";
const dataFim = "31/01/2024";
const orgao = "52000";

const options = {
  method: 'GET',
  url: `https://api.portaldatransparencia.gov.br/api-de-dados/licitacoes`,
  qs: {
    dataInicial: dataInicio, 
    dataFinal: dataFim,
    codigoOrgao: orgao,
    pagina: 1
  },
  headers: {
    'accept': 'application/json',
    'chave-api-dados': apiKey,
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64)'
  },
  json: true
};

try {
  const response = await this.helpers.httpRequest(options);

  if (!response || response.length === 0) {
    return [{ 
      json: { 
        status: "vazio", 
        msg: `Sem dados encontrados para ${orgao} em ${dataInicio}` 
      } 
    }];
  }

  // IMPORTANTE: Retornamos os dados garantindo que o campo 'id' exista
  return response.map(item => ({ json: item }));

} catch (error) {
  return [{
    json: {
      status: "erro",
      codigo: error.response ? error.response.statusCode : "Conexao",
      mensagem: error.message,
      detalhe: error.response ? JSON.stringify(error.response.body) : "Erro na requisição"
    }
  }];
}

const apiKey = 'a872c438262a647dfe89cd3c531c2cb0'.trim();

// 1. Tentamos pegar o número do processo de diferentes caminhos possíveis na API
const item = $input.item.json;
const numProcesso = item.numeroProcesso || 
                    item.licitacao?.numeroProcesso || 
                    item.processo || 
                    "";

const codOrgao = "52000"; 

// Se não achou número de processo, vamos logar o que veio para entender o erro
if (!numProcesso || numProcesso === "") {
    return [{ 
        json: { 
            status: "debug_necessario", 
            mensagem: "Não encontramos o campo numeroProcesso no objeto anterior",
            o_que_recebi: item 
        } 
    }];
}

const options = {
  method: 'GET',
  url: `https://api.portaldatransparencia.gov.br/api-de-dados/despesas/por-processo-licitatorio`,
  qs: {
    pagina: 1,
    numeroProcesso: numProcesso.trim(),
    codigoOrgao: codOrgao
  },
  headers: {
    'accept': 'application/json',
    'chave-api-dados': apiKey,
    'User-Agent': 'Mozilla/5.0'
  },
  json: true
};

try {
  const response = await this.helpers.httpRequest(options);

  if (!response || response.length === 0) {
    return [{ json: { status: "vazio", processo_buscado: numProcesso, msg: "Processo existe, mas sem pagamentos ainda." } }];
  }

  return response.map(gasto => ({
    json: {
      id: gasto.id, 
      licitacao_id: item.id, // Vínculo com a tabela de licitações
      data_pagamento: gasto.dataReferencia,
      valor_pago: gasto.valorApurado,
      fase_despesa: gasto.faseDespesa,
      favorecido_nome: gasto.favorecido?.nome || "Não informado",
      favorecido_documento: gasto.favorecido?.cpfCnpjFormatado || "---",
      orgao_nome: gasto.unidadeGestora?.orgaoMaximo?.nome || "Ministério da Defesa",
      link_fonte: `https://portaldatransparencia.gov.br/despesas/pagamento/${gasto.id}`
    }
  }));

} catch (error) {
  return [{ 
    json: { 
      status: "erro_vinculo", 
      codigo: error.response ? error.response.statusCode : "???",
      msg: error.message,
      processo_tentado: numProcesso
    } 
  }];
}
